with:
  # Build a single complex sentence from all triples
      clauses = []
      for t in triples:
          tmpl = clause_map.get(t.predicate)
          if tmpl:
              clause_body = tmpl.format(object=t.object)
          else:
              # fallback generic clause
              clause_body = f"{t.predicate.replace('_', ' ')} {t.object}"
          clause = f"{t.subject} {clause_body}"
          clauses.append(clause)

      if not clauses:
          return ""
      if len(clauses) == 1:
          return f"{clauses[0]}."
      # join with commas and an 'and' before the last clause
      return f"{', '.join(clauses[:-1])}, and {clauses[-1]}."
